"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[470],{9030:e=>{e.exports=JSON.parse('{"functions":[{"name":"create","desc":"Returns a `(tag, enabled) -> { info, warn }` constructor bound to\\n`devEnvName`. Loggers built from it only emit output when running\\ninside a matching local dev environment **and** `enabled` is true.","params":[{"name":"devEnvName","desc":"Identifier passed to [IsLocalDev] and used as the log prefix.","lua_type":"string"}],"returns":[{"desc":"","lua_type":"(tag: string, enabled: boolean) -> { info: (...any) -> (), warn: (...any) -> () }"}],"function_type":"static","source":{"line":70,"path":"plugin/elttob-log/init.luau"}}],"properties":[],"types":[],"name":"ElttobLog","desc":"A tagged logger that only emits output in a local development\\nenvironment, detected via [IsLocalDev]. Unbracketed and bracketed GUIDs\\nare replaced with short emoji-based identifiers in log messages so they\\nstay readable in the Output window.\\n\\nThe module exports a factory: pass it your local dev environment name\\nonce, and it returns a `create(tag, enabled)` function for opening\\nscoped loggers.\\n\\n```lua\\nlocal makeLog = require(path.to.Log)(\\"MyPlugin\\")\\nlocal log = makeLog(\\"Network\\", true)\\nlog.info(\\"hello\\")  -- only prints in local dev\\n```","source":{"line":22,"path":"plugin/elttob-log/init.luau"}}')}}]);